// syncResourcePath maps resource names to their actual API endpoint paths.
// For REST APIs this is typically "/<resource>". For non-REST APIs (e.g., Steam)
// this preserves the actual endpoint path like "/ISteamApps/GetAppList/v2".
func syncResourcePath(resource string) string {
	paths := map[string]string{
		"ability":                   "/api/v2/ability/",
		"berry":                     "/api/v2/berry/",
		"berry-firmness":            "/api/v2/berry-firmness/",
		"berry-flavor":              "/api/v2/berry-flavor/",
		"characteristic":            "/api/v2/characteristic/",
		"contest-effect":            "/api/v2/contest-effect/",
		"contest-type":              "/api/v2/contest-type/",
		"egg-group":                 "/api/v2/egg-group/",
		"encounter-condition":       "/api/v2/encounter-condition/",
		"encounter-condition-value": "/api/v2/encounter-condition-value/",
		"encounter-method":          "/api/v2/encounter-method/",
		"evolution-chain":           "/api/v2/evolution-chain/",
		"evolution-trigger":         "/api/v2/evolution-trigger/",
		"gender":                    "/api/v2/gender/",
		"generation":                "/api/v2/generation/",
		"growth-rate":               "/api/v2/growth-rate/",
		"item":                      "/api/v2/item/",
		"item-attribute":            "/api/v2/item-attribute/",
		"item-category":             "/api/v2/item-category/",
		"item-fling-effect":         "/api/v2/item-fling-effect/",
		"item-pocket":               "/api/v2/item-pocket/",
		"language":                  "/api/v2/language/",
		"location":                  "/api/v2/location/",
		"location-area":             "/api/v2/location-area/",
		"machine":                   "/api/v2/machine/",
		"meta":                      "/api/v2/meta/",
		"move":                      "/api/v2/move/",
		"move-ailment":              "/api/v2/move-ailment/",
		"move-battle-style":         "/api/v2/move-battle-style/",
		"move-category":             "/api/v2/move-category/",
		"move-damage-class":         "/api/v2/move-damage-class/",
		"move-learn-method":         "/api/v2/move-learn-method/",
		"move-target":               "/api/v2/move-target/",
		"nature":                    "/api/v2/nature/",
		"pal-park-area":             "/api/v2/pal-park-area/",
		"pokeathlon-stat":           "/api/v2/pokeathlon-stat/",
		"pokedex":                   "/api/v2/pokedex/",
		"pokemon":                   "/api/v2/pokemon/",
		"pokemon-color":             "/api/v2/pokemon-color/",
		"pokemon-form":              "/api/v2/pokemon-form/",
		"pokemon-habitat":           "/api/v2/pokemon-habitat/",
		"pokemon-shape":             "/api/v2/pokemon-shape/",
		"pokemon-species":           "/api/v2/pokemon-species/",
		"region":                    "/api/v2/region/",
		"stat":                      "/api/v2/stat/",
		"super-contest-effect":      "/api/v2/super-contest-effect/",
		"type":                      "/api/v2/type/",
		"version":                   "/api/v2/version/",
		"version-group":             "/api/v2/version-group/",
	}
	if p, ok := paths[resource]; ok {
		return p
	}
	return "/" + resource
}

func extractID(obj map[string]any) string {
	for _, key := range []string{"id", "ID", "ticker", "event_ticker", "series_ticker", "key", "code", "uid", "uuid", "slug", "name"} {
		if v, ok := obj[key]; ok {
			s := fmt.Sprintf("%v", v)
			if s != "" && s != "<nil>" {
				return s
			}
		}
	}
	return ""
}
